function StructSettingInfo:StructSettingInfo()
    self.refId = 0
    self.count = 0
    self.moreInfo = ""
    self.maxLimit = 0
    self.consume = ""
    self.surplusCount = 0
    self.subOption = {}
    self.subOptionMap = {}
end

function StructSettingInfo:CreateByPb(pb)
    --- 助手设置表refId
    self.refId = pb.refId

    --- 设置次数；当为开关类型时，1=开启，0=关闭
    self.count = pb.count

    --- 其他数据
    self.moreInfo = pb.moreInfo

    --- 最大次数限制
    self.maxLimit = pb.maxLimit

    --- 消耗（通用道具格式，暂定于设置次数挂钩）
    self.consume = pb.consume

    --- 剩余次数
    self.surplusCount = pb.surplusCount

    --- 子设置信息
    self.subOption = {}
    self.subOptionMap = {}
    for i,v in ipairs(pb.subOption) do
        local subOption = StructSubOption:New()
        subOption:CreateByPb(v)
        table.insert(self.subOption,subOption)
        self.subOptionMap[subOption.refId] = subOption
    end
end

return StructSettingInfo